INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027b8fe3c98b0941765993', '老牌酒店的品质保证，第一次入住花园酒店，感觉很贴心，免费升级了套房，送了入住果盘、小孩洗漱套装、冰箱贴、手绘地图，还给小朋友送了一只小羊玩偶，特别可爱。酒店虽然有点年份，但整体还是干净整洁，大堂很华丽，很多广州的装饰，还有一个博物馆可以了解酒店的背景和文化。瀑布餐厅氛围感很好，可以看到花草繁茂的后花园和流水瀑布。整体服务很到位，客房、餐厅都有充足的服务人员，前台的Mancy和James特别nice，有种宾至如归的感觉。', '["https://dimg04.c-ctrip.com/images/0232q12000exblzpj3E7F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000exbmjue74CE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232m12000exblcb42750_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000exblj30B4F3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236o12000exbjrjy83AC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000exbkgcd61DA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232v12000exblpv9FD21_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-28', '花园双床房', '双床房', '家庭亲子', 211, 0, 1, 9, '["前台服务","整体满意度","卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况'),
('68027b8fe3c98b0941765994', '酒店环境优美，瀑布餐厅和后院的小花园都很有特色，工作人员服务热情，房间干净卫生，稍小设施也有点老旧。早餐非常丰富，还有很多外国人，总体还是非常不错的。', '["https://dimg04.c-ctrip.com/images/0237012000f56syto175E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230j12000f56wmryD338_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t12000f56w3ej4F59_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-08-16', '花园双床房', '双床房', '家庭亲子', 75, 0, 14, 7, '["餐饮设施","整体满意度","卫生状况"]'::jsonb, '餐饮设施', '整体满意度', '卫生状况'),
('68027b8fe3c98b0941765995', '服务非常好！里面的餐也很正宗，地理位置很好，地铁站出口就是，很方便！适合带孩子！', '["https://dimg04.c-ctrip.com/images/0234l12000f02o4etAB56_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000f02rruzD406_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000f02nhwyBD2E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236c12000f02jv4l391E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236c12000f02iecu70EC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000f02mqu50168_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232212000f02j4y3D7CE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236l12000f02idxgDA33_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-04', '花园大床房', '大床房', '朋友出游', 40, 0, 9, 7, '["交通便利性","餐饮设施","前台服务"]'::jsonb, '交通便利性', '餐饮设施', '前台服务'),
('68027b8fe3c98b0941765996', '来过很多次了，这边的人气跟地理位置都让我很喜欢，也是一个非常有老广气息的酒店，这边也有挺出名的餐厅，还有一进门就能见到身穿金色衣服的小姐姐，交谈过后发现他们原来是花园白金大使，让我印象深刻的是一个叫小何的大使，服务真的很不错??', '["https://dimg04.c-ctrip.com/images/0234l12000jf4g5en1CC8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234412000jf4k8gw8A04_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-03-30', '花园大床房', '大床房', '家庭亲子', 114, 0, 5, 7, '["前台服务","周边配套","餐饮设施"]'::jsonb, '前台服务', '周边配套', '餐饮设施'),
('68027b8fe3c98b0941765997', '房间很好，适合小朋友，还有小朋友拖鞋牙刷，打电话给前台，送来的非常快。还有铅笔橡皮尺子卷笔刀。小胶棒，小羊商铺ADA LINA 迎宾LIVEN 都很好。来之前看到很多差评，有点忐忑，但是来了之后，很好。小朋友说非常好，酒店特别大', '["https://dimg04.c-ctrip.com/images/0235i12000duj0gdc88B2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000duiom9v04B2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231212000duirimu909A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232e12000duj0qyh83F2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000duirea34067_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-01', '花园双床房', '双床房', '家庭亲子', 114, 0, 6, 7, '["房间设施","前台服务","整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度'),
('68027b8fe3c98b0941765998', '91年的时候路过花园酒店，觉得好高端好大气，就非常想去，各种阴差阳错，一拖就拖到了30年后。后花园，锦鲤酒吧感觉都非常好，早餐是在旋转餐厅吃的，风景不错，还非常丰盛，牛腩也很好吃。前台服务很好，很热情，回访的小晴态度也很好，值得表扬，有机会一定再来。', '["https://dimg04.c-ctrip.com/images/0235e12000fil8dnd93CD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000fikq31e7D2B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000fil2y3309E9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-12', '红棉大床套房', '套房', '家庭亲子', 125, 1, 18, 7, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027b8fe3c98b0941765999', '大堂美轮美奂，瀑布餐厅震撼。太喜欢花园酒店了', '["https://dimg04.c-ctrip.com/images/0236c12000fgkrl9b4FAD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000fgk0plp6854_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-08', '花园双床房', '双床房', '家庭亲子', 22, 0, 13, 4, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68027b99e3c98b094176599a', '房间设施很好，餐饮很精致，服务员很多，随时出现在你需要的时候。', '["https://dimg04.c-ctrip.com/images/0230e12000f7cu8m9A5A4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-22', '花园大床房', '大床房', '家庭亲子', 31, 0, 4, 6, '["房间设施","餐饮设施","前台服务"]'::jsonb, '房间设施', '餐饮设施', '前台服务'),
('68027b99e3c98b094176599b', '房间干净整齐，服务很棒。环境配得上五星级，后花园飞瀑流泉，游鱼欢悦，绿树蓬蓬。酒店建筑设计更是独到有文化韵味。', '["https://dimg04.c-ctrip.com/images/0232r12000ekih86o2849_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000ekigx8e6009_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000ekif2lzCBD3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000ekih2gr3342_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000ekiah8mC0D4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000ekif4z4DFE5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236e12000ekier2g1946_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000ekijjneFDFB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231212000eki3z02BF81_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-25', '红棉大床套房', '套房', '朋友出游', 55, 1, 2, 8, '["整体满意度","卫生状况","公共设施"]'::jsonb, '整体满意度', '卫生状况', '公共设施'),
('68027b99e3c98b094176599c', '老牌五星级酒店，虽然有将近四十年了，但内部装修风格和质感比大部分现在新的酒店都好多了，环境不用说，对得起花园酒店的名字，服务不知道是不是广交会的缘故，住的几天都特别好，早餐分别吃了30楼旋转餐厅和一楼瀑布餐厅的，东西差不多，都很丰富，总体对这几天的入住很满意', '["https://dimg04.c-ctrip.com/images/0236w12000dumf8rxCDCF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231e12000dulxq14CC90_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000dumpl127C28_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-02', '花园大床房', '大床房', '家庭亲子', 129, 0, 24, 9, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('68027b99e3c98b094176599d', '酒店的环境真的没话说，不愧是老牌酒店，大厅富丽堂皇；
唯一的缺点就是房间有点点小，但整体房间设施都不错，干净、舒服。', '["https://dimg04.c-ctrip.com/images/0234d12000fouysvj71C8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231112000fouv2q6E87A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-22', '花园大床房', '大床房', '朋友出游', 58, 0, 13, 7, '["房间设施","整体满意度","卫生状况"]'::jsonb, '房间设施', '整体满意度', '卫生状况'),
('68027b99e3c98b094176599e', '代客户预订，还给升级了房间！客户感觉很满意！今天又续了一天！
作为广州的老五星，服务非常好！连每个楼层都配有服务员指引！厉害厉害！', '["https://dimg04.c-ctrip.com/images/0233212000eicoit5786E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230c12000eicvjwjCE1F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000eicylwf62A4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-18', '花园大床房', '大床房', '代人预订', 65, 1, 124, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027b99e3c98b094176599f', '对海外华人港澳台人来说最知名的内地酒店就是广州花园酒店，非常多外国客入住。位于市中心老城区位置得天独厚，服务也很好，check in等待 会送上可乐饮料。员工积极主动，广交会房间紧张时期酒店还免费给我升级了套房，可能我是携程高级会员的缘故吧，总之非常感谢酒店。', '["https://dimg04.c-ctrip.com/images/0230i12000dtqyyd10B04_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v12000dtqhh9o4954_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000dtrc8lo1E5C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235112000dtqvg987D7C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232k12000dtqfm2r7FE4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000dtql49eDA5A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235n12000dtqxxgt4D18_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-30', '花园大床房', '大床房', '情侣出游', 130, 1, 93, 8, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027b99e3c98b09417659a0', '第一次入住白金五星级酒店，全国只有三家，这家服务真的好，服务员是很有包容心的那种，知道不说破给客人尊荣！那瀑布是绝绝子，让人很迷恋，前厅经理给我们房间升级了套房双床，送了一份早餐，第二天去用早餐，因为一份早餐的原因在30楼旋转餐厅打包两个人享用了，服务员热情的帮我打了包！后来我又去了30楼和1楼另外两个早餐厅，畅通无阻！管理员知道却默许了，让我们很舒服！去了花园博物馆，真的学到了，那份底蕴无需多言处处渗透！在楼层上电梯打开就有服务员热情的送上红茶指引，第二次上去就记得我住的房间，细节到位，下次有机会还会去花园酒店，尝尝米其林餐厅美食，在早餐厅听瀑布声，去花园酒店博物馆里记记酒店发展史！', '["https://dimg04.c-ctrip.com/images/0235q12000dwpekw00370_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236012000dwp95l07F67_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000dwpe03jEE43_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000dwpdm3i777E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000dwpaut9E75F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000dwp9yng0A46_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230h12000dwpda3m7E98_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000dwpas680E38_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000dwpd3zl83B7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-07', '花园双床房', '双床房', '商务出差', 296, 0, 6, 9, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('68027b99e3c98b09417659a2', '在花园酒店吃住都非常的舒服，花园酒店不愧是花园酒店，酒店的花都非常的漂亮。最让人印象深刻的就是30楼的行政酒廊，这里的风景非常优美，音乐听着也很让人动听。行政酒廊的mignon的笑容很甜美，服务很贴心，ken得服务也非常的周到。让我有一个非常不错的用餐体验，下次旅游还会选择这家酒店。', '["https://dimg04.c-ctrip.com/images/0235112000dtkzjm5DA94_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236012000dtkkaye8F09_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000dtl2t61AF00_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-29', '花园双床房', '双床房', '家庭亲子', 142, 0, 4, 8, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027b99e3c98b09417659a3', '干净卫生，虽然有点旧', '["https://dimg04.c-ctrip.com/images/0235u12000g19nhli375C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234e12000g19v86q6CF3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000g19n1l45F08_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-08', '花园双床房', '双床房', '家庭亲子', 10, 0, 4, 4, '["卫生状况","房间设施"]'::jsonb, '卫生状况', '房间设施', NULL),
('68027ba4e3c98b09417659a4', '房间很大 两米大床很舒服 服务很周到 前台送了小朋友早餐 下次还会来', '["https://dimg04.c-ctrip.com/images/0231a12000f32ht1pCFE4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000f32id7rBFC6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000f32bktb93D2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-11', '红棉大床套房', '套房', '家庭亲子', 34, 0, 4, 6, '["房间设施","前台服务","整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度'),
('68027ba4e3c98b09417659a5', '酒店房间挺大的，一家四口住得下，离地铁站非常近，点外卖也很方便，有酒店后面中国银行外卖柜，酒店里还有博物馆值得一看', '["https://dimg04.c-ctrip.com/images/0231h12000en289o45C00_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000en2e6l212C8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234n12000en29uy71A9C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233812000en28p6n9C58_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-01', '红棉双床套房', '套房', '家庭亲子', 57, 0, 10, 7, '["交通便利性","周边配套","房间设施"]'::jsonb, '交通便利性', '周边配套', '房间设施'),
('68027ba4e3c98b09417659a6', '非常非常满意的一次入住，酒店就在市中心，离地铁站也近，去哪里都特别方便。特别感谢Rebecca小钟，看我们又老又小，拖家带口的，主动提供了很多帮助，真心特别满意。行政酒廊的下午茶和欢乐时光我们也特别喜欢。整个酒店有好多外国人进出，非常国际化，还可以喂锦鲤，孩子喜欢的不得了！', '["https://dimg04.c-ctrip.com/images/0236812000hwsat2s65B9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000hwtdgac2A7D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000hwtgdfaCE40_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-19', '红棉双床套房', '套房', '家庭亲子', 137, 0, 4, 9, '["整体满意度","交通便利性","前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务'),
('68027ba4e3c98b09417659a7', '这个酒店环境美爆了', '["https://dimg04.c-ctrip.com/images/0234c12000fzlckhg1259_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-05', '花园双床房', '双床房', '家庭亲子', 9, 0, 16, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027ba4e3c98b09417659a8', '酒店位置不错，无论是出游还是觅食都很方便，但是房型实在实在是有点太小了，第一次见到一个五星酒店、浴缸和淋浴房局促在小小的一个空间里，确实也是没想到的。。。不清楚是不是广交会的缘故，大堂晚上会有美丽的小姐姐跳舞，贴心的管家小姐姐还帮我们插了鲜花，感恩ing！', '["https://dimg04.c-ctrip.com/images/0230f12000dvmr7blB452_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000dvmqneh9472_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000dvmrdalD616_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233b12000dvmqvxc18B3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m12000dvmrdp7E206_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000dvmqvemD7E0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-05-04', '花园双床房', '双床房', '家庭亲子', 128, 1, 5, 8, '["周边配套","房间设施","前台服务"]'::jsonb, '周边配套', '房间设施', '前台服务'),
('68027ba4e3c98b09417659a9', '特别感谢前台小姐姐Ann在我9/22号办理入住时的热情细致的接待', '["https://dimg04.c-ctrip.com/images/0232y12000fqa8sq9A3CE_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233y12000fqa8ss5EBE1_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-09-24', '花园大床房', '大床房', '商务出差', 32, 0, 1, 5, '["前台服务"]'::jsonb, '前台服务', NULL, NULL),
('68027ba4e3c98b09417659aa', '前台服务态度非常好，办理入住和退房也迅速，生日升级了套房。晚上瀑布自助餐，种类少。门口因为兴建地铁，很难去建设六马路。', '["https://dimg04.c-ctrip.com/images/0236412000ewapuet4B9E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236v12000ewawj596AD4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235w12000ewanp0g9E78_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-25', '花园双床房', '双床房', '家庭亲子', 59, 0, 12, 7, '["前台服务","退房/入住效率","交通便利性"]'::jsonb, '前台服务', '退房/入住效率', '交通便利性'),
('68027ba4e3c98b09417659ab', '入住两天，感受都还不错，交通也很方便，打车地铁都很便捷。周围美食也很多，广州酒家，点都德，赵记传承～酒店服务非常不错，询问去澳门大巴，服务员会亲自带着走老远到上车的地点！小颜服务热心体贴到位！谢谢她的帮助', '["https://dimg04.c-ctrip.com/images/0236z12000jis5dzf8E46_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232i12000jit5qw99D6E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-03', '花园双床房', '双床房', '商务出差', 102, 0, 4, 8, '["交通便利性","周边配套","前台服务"]'::jsonb, '交通便利性', '周边配套', '前台服务'),
('68027ba4e3c98b09417659ac', '酒店位置好，出行便利。早餐丰盛服务热情。', '["https://dimg04.c-ctrip.com/images/0231u12000fn8lpld7316_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000fn8ai8qBDBD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000fn8lxlk382F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-19', '花园大床房', '大床房', '家庭亲子', 20, 0, 5, 5, '["交通便利性","餐饮设施","前台服务"]'::jsonb, '交通便利性', '餐饮设施', '前台服务'),
('68027ba4e3c98b09417659ad', '中秋佳节来广州避台风选择了广州花园酒店
没有额外加价 性价比直接拉满
贝聿铭大师设计的雨棚穹顶充满浪漫感
但更令人惊喜的是酒店服务人员从前台到客房部到餐饮部都热情礼貌管理有素

感谢客房部的Adan和Marry金芳
给予我们整洁安静的客房环境
让我和我的家人宾至如归

感谢行政酒廊的主管Carrie女士
以及她的伙伴Rose、Cathy、Kitty
给予我和我的家人热情舒适的服务

有机会再来广州还会选择花园酒店入住的', '["https://dimg04.c-ctrip.com/images/0236812000fma1jka832C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000fmamk90B575_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236s12000fmb0tue0726_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000fmaum3157D6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t12000fmaum371401_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000fmba9gb9561_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-18', '花园大床房', '大床房', '家庭亲子', 211, 0, 1, 9, '["整体满意度","前台服务","客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务'),
('68027bb1e3c98b09417659ae', '大厅超美，房间舒适，还有小点心，客房服务周到，服务热情，后花园打卡好去处', '["https://dimg04.c-ctrip.com/images/0232u224x8wvsm6920AAA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02321224x8wvrwgbiFEDD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q224x8wvrubwi2FA7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-09', '花园大床房', '大床房', '家庭亲子', 36, 0, 13, 6, '["客房服务","整体满意度","公共设施"]'::jsonb, '客房服务', '整体满意度', '公共设施'),
('68027bb1e3c98b09417659af', '房间物品补充及时。
行政酒廊的Carrie和mira服务热情周到，很棒！', '["https://dimg04.c-ctrip.com/images/0232u12000f969t7zD73D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.3, 4, '2024-08-26', '花园大床房', '大床房', '商务出差', 36, 0, 1, 5, '["客房服务","餐饮设施"]'::jsonb, '客房服务', '餐饮设施', NULL),
('68027bb1e3c98b09417659b0', '环境很美 服务也挺好 就是换气不好导致房间浴室有味 浴缸龙头的周围也能看出设施老旧', '["https://dimg04.c-ctrip.com/images/0235812000eupe8f207A0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234512000euperr19800_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235212000eupedvxB55F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234b12000eupef8wA561_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2024-07-21', '红棉双床套房', '套房', '家庭亲子', 41, 0, 5, 7, '["房间设施","卫生状况"]'::jsonb, '房间设施', '卫生状况', NULL),
('68027bb1e3c98b09417659b1', '酒店本身就是一个景点，最惊艳的是四楼的博物馆！', '["https://dimg04.c-ctrip.com/images/0233112000f9c3xas4040_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000f9c36e0E714_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000f9ce6039CEC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000f9c286p50D8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-26', '花园双床房', '双床房', '家庭亲子', 23, 0, 9, 5, '["公共设施"]'::jsonb, '公共设施', NULL, NULL),
('68027bb1e3c98b09417659b2', '和好友分别带孩子去长隆玩，选择了交通方便的市区，不亏是花城，酒店处处都是景，很多拍照打卡、拍摄婚纱的，满眼的绿植、鲜花视觉放松、漫步其中，心情愉悦，标准客房2大2小足够用，紧凑、够用、舒适、卫生！酒店本身就是小景点！', '["https://dimg04.c-ctrip.com/images/0233j12000ekezykq3FB7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231112000ekf56te21B6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000ekeyg6o2E34_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236312000ekf47qy0D91_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231612000eketez63B5E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000ekevdgyF625_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230512000ekexpk81381_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000ekf2b8kAAE4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000ekeui1422BB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-24', '花园双床房', '双床房', '朋友出游', 108, 0, 16, 8, '["交通便利性","周边配套","整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度'),
('68027bb1e3c98b09417659b3', '帮我升级了房型，谢谢
但送的小羊没有了，可惜', '["https://dimg04.c-ctrip.com/images/0236l12000f8yg7mi3BBE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234n12000f8yeuh1F4DC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-25', '红棉大床套房', '套房', '朋友出游', 22, 0, 15, 4, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027bb1e3c98b09417659b4', '再次来到花园酒店，不再是只有情怀在牵引着我，开门小哥哥的笑容，金色小姐姐的迎接，前台妹妹的有求必应，房间的干净卫生，每一样都是能与白金五星的对标！单独表扬感谢Jin经理的帮助，和让我感受到花园的温暖！作为广州人，花园酒店已经不再是记忆中的大酒店，而且有温度与回忆，传承与融合的文化载体！我会再来的，也会与亲朋好友再来的！', '["https://dimg04.c-ctrip.com/images/0234q12000jbudz2m82B6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000jbv25e0D2F3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235j12000jbv9gml446B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-26', '花园双床房', '双床房', '独自旅行', 160, 0, 13, 9, '["前台服务","整体满意度","卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况'),
